#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/stat.h>
#include <unistd.h>

// path and filename sizes
#define PATH_LEN 256
#define MSG_LEN 1024
#define MAX_FILES 128
#define MAX_COMMITS 256
#define FILE_NAME_LEN 128

typedef struct FileNode {
    char filename[FILE_NAME_LEN];
    struct FileNode* next;
} FileNode;

typedef struct CommitNode {
    int id;
    char message[MSG_LEN];
    FileNode* files;
    struct CommitNode* next;
} CommitNode;

CommitNode* commit_head = NULL;
FileNode* index_head = NULL;
int current_commit = -1;

// Helper to check if .minigit exists
int is_repo_initialized() {
    struct stat st = {0};
    return (stat(".minigit", &st) == 0 && S_ISDIR(st.st_mode));
}

// Helper to create .minigit dir
void init_repo() {
    if (is_repo_initialized()) {
        printf("Repository already initialized.\n");
        return;
    }
    mkdir(".minigit", 0700);
    mkdir(".minigit/commits", 0700);
    printf("Initialized empty MiniGit repository in .minigit\n");
}

// Adds a file to index (not copy, just track by name)
void add_file(const char *filename) {
    if (!is_repo_initialized()) {
        printf("Not a minigit repository.\n");
        return;
    }
    // Check if file exists
    if (access(filename, R_OK) != 0) {
        printf("File '%s' does not exist.\n", filename);
        return;
    }
    // Check if already tracked
    for (FileNode *p = index_head; p; p = p->next) {
        if (strcmp(p->filename, filename) == 0) {
            printf("File already added.\n");
            return;
        }
    }
    FileNode *node = malloc(sizeof(FileNode));
    strncpy(node->filename, filename, FILE_NAME_LEN-1);
    node->filename[FILE_NAME_LEN-1] = 0;
    node->next = index_head;
    index_head = node;
    printf("Added '%s' to index.\n", filename);
}

// Removes file from index
void remove_file(const char *filename) {
    if (!is_repo_initialized()) {
        printf("Not a minigit repository.\n");
        return;
    }
    FileNode **pp = &index_head;
    while (*pp) {
        if (strcmp((*pp)->filename, filename) == 0) {
            FileNode *to_free = *pp;
            *pp = (*pp)->next;
            free(to_free);
            printf("Removed '%s' from index.\n", filename);
            return;
        }
        pp = &((*pp)->next);
    }
    printf("File not found in index.\n");
}

// Save index to .minigit/index
void save_index() {
    FILE *f = fopen(".minigit/index", "w");
    if (!f) return;
    for (FileNode *p = index_head; p; p = p->next) {
        fprintf(f, "%s\n", p->filename);
    }
    fclose(f);
}

// Load index from .minigit/index
void load_index() {
    FileNode *node, *next;
    while (index_head) {
        next = index_head->next;
        free(index_head);
        index_head = next;
    }
    FILE *f = fopen(".minigit/index", "r");
    if (!f) return;
    char buf[FILE_NAME_LEN];
    while (fgets(buf, FILE_NAME_LEN, f)) {
        size_t len = strlen(buf);
        if (len>0 && buf[len-1]=='\n') buf[len-1] = 0;
        node = malloc(sizeof(FileNode));
        strncpy(node->filename, buf, FILE_NAME_LEN);
        node->next = index_head;
        index_head = node;
    }
    fclose(f);
}

// Commit: copy all index files to .minigit/commits/c_N/ and log message
void commit(const char *message) {
    if (!is_repo_initialized()) {
        printf("Not a minigit repository.\n");
        return;
    }
    if (!index_head) {
        printf("Nothing to commit (index is empty).\n");
        return;
    }
    current_commit++;
    char commit_dir[PATH_LEN];
    snprintf(commit_dir, PATH_LEN, ".minigit/commits/c_%d", current_commit);
    mkdir(commit_dir, 0700);

    // Copy tracked files to commit dir
    for (FileNode *p = index_head; p; p = p->next) {
        char dest[PATH_LEN];
        snprintf(dest, PATH_LEN, "%s/%s", commit_dir, p->filename);
        FILE *fin = fopen(p->filename, "rb");
        if (!fin) continue;
        FILE *fout = fopen(dest, "wb");
        if (!fout) { fclose(fin); continue; }
        char buf[1024];
        size_t n;
        while ((n=fread(buf, 1, sizeof(buf), fin)) > 0) {
            fwrite(buf, 1, n, fout);
        }
        fclose(fin);
        fclose(fout);
    }
    // Log commit
    FILE *f = fopen(".minigit/log", "a");
    if (f) {
        fprintf(f, "%d:%s\n", current_commit, message);
        fclose(f);
    }

    // Save a snapshot of index for the commit
    char idxfn[PATH_LEN];
    snprintf(idxfn, PATH_LEN, "%s/index", commit_dir);
    FILE* fidx = fopen(idxfn, "w");
    if (fidx) {
        for (FileNode *p = index_head; p; p = p->next) {
            fprintf(fidx, "%s\n", p->filename);
        }
        fclose(fidx);
    }

    save_index();
    printf("Committed as commit #%d: %s\n", current_commit, message);
}

// Print status (index)
void status() {
    if (!is_repo_initialized()) {
        printf("Not a minigit repository.\n");
        return;
    }
    printf("Tracked files:\n");
    int cnt = 0;
    for (FileNode *p = index_head; p; p = p->next) {
        printf("  %s\n", p->filename);
        cnt++;
    }
    if (!cnt) printf("  (none)\n");
}

// Print log (all commits)
void show_log() {
    if (!is_repo_initialized()) {
        printf("Not a minigit repository.\n");
        return;
    }
    FILE *f = fopen(".minigit/log", "r");
    if (!f) {
        printf("No commits yet.\n");
        return;
    }
    char buf[MSG_LEN+32];
    while (fgets(buf, sizeof(buf), f)) {
        size_t len = strlen(buf);
        if (len>0 && buf[len-1]=='\n') buf[len-1]=0;
        printf("%s\n", buf);
    }
    fclose(f);
}

// MAIN
int main(int argc, char *argv[]) {
    if (argc < 2) {
        printf("Usage: ./minigit <command> [args ...]\n");
        return 1;
    }
    // Load index before acting, unless for 'init'
    if (strcmp(argv[1], "init") != 0)
        load_index();

    if (strcmp(argv[1], "init") == 0)
        init_repo();
    else if (strcmp(argv[1], "add") == 0) {
        if (argc < 3) { printf("Specify a file to add.\n"); return 1; }
        add_file(argv[2]);
        save_index();
    }
    else if (strcmp(argv[1], "remove") == 0) {
        if (argc < 3) { printf("Specify a file to remove.\n"); return 1; }
        remove_file(argv[2]);
        save_index();
    }
    else if (strcmp(argv[1], "commit") == 0) {
        if (argc < 3) { printf("Specify a commit message.\n"); return 1; }
        // Compose message from argv[2...]
        char msg[MSG_LEN]="";
        for (int i = 2; i < argc; ++i) {
            if (i > 2) strcat(msg, " ");
            strcat(msg, argv[i]);
        }
        commit(msg);
    }
    else if (strcmp(argv[1], "status") == 0)
        status();
    else if (strcmp(argv[1], "log") == 0)
        show_log();
    else {
        printf("Unknown command: %s\n", argv[1]);
        return 1;
    }
    return 0;
}
